async function recordRevenueEvent(env, event) {
  const id = crypto.randomUUID();
  try {
    await env.DB.prepare(`
      INSERT INTO revenue_events
        (id, source, amount, user_id, email, metadata, payment_id, created_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, datetime('now'))
    `).bind(
      id,
      event.source || "unknown",
      event.amount || 0,
      event.user_id || null,
      event.email || null,
      event.metadata || null,
      event.payment_id || null
    ).run();
    return { success: true, id };
  } catch (err3) {
    try {
      const fallbackKey = `rev:fallback:${id}`;
      await env.SECURITY_HUB_KV?.put(
        fallbackKey,
        JSON.stringify({ ...event, id, ts: Date.now() }),
        { expirationTtl: 86400 * 7 }
        // keep 7 days
      );
    } catch {
    }
    return { success: false, error: err3.message, id };
  }
}
