async function trackEvent(env, eventType, module = null, userId = null, ip = null, metadata = {}) {
  if (!env?.DB) return;
  try {
    const id = crypto.randomUUID?.() || Date.now().toString(36) + Math.random().toString(36).slice(2);
    await env.DB.prepare(
      `INSERT INTO analytics_events (id, event_type, module, user_id, ip, metadata, created_at)
       VALUES (?, ?, ?, ?, ?, ?, datetime('now'))`
    ).bind(
      id,
      eventType,
      module || null,
      userId || null,
      ip ? ip.slice(0, 45) : null,
      // Truncate IPv6
      metadata ? JSON.stringify(metadata) : null
    ).run();
  } catch (e) {
    console.warn("[Analytics] trackEvent failed:", e?.message);
  }
}
