    401: "ERR_UNAUTHORIZED",
    403: "ERR_FORBIDDEN",
    404: "ERR_NOT_FOUND",
    409: "ERR_CONFLICT",
    422: "ERR_UNPROCESSABLE",
    429: "ERR_QUOTA_EXCEEDED",
    500: "ERR_INTERNAL",
    502: "ERR_BAD_GATEWAY",
    503: "ERR_SERVICE_UNAVAILABLE"
