async function getDueEmails(env, limit = 50) {
  try {
    const result = await env.DB.prepare(`
      SELECT es.*, l.name, l.domain, l.plan, l.lead_score
      FROM email_sequences es
      JOIN leads l ON l.email = es.email
      WHERE es.status = 'active'
        AND es.next_send_at <= datetime('now')
      LIMIT ?
    `).bind(limit).all();
    return result.results || [];
  } catch (err3) {
    console.error("[emailEngine] getDueEmails error:", err3.message);
    return [];
  }
}
