async function advanceSequence(env, sequenceRowId, nextStep, delayDays) {
  const nextSendAt = new Date(Date.now() + delayDays * 864e5).toISOString();
  const isDone = nextStep >= 4;
  try {
    await env.DB.prepare(`
      UPDATE email_sequences
      SET current_step = ?,
          status = ?,
          next_send_at = ?,
          last_sent_at = datetime('now')
      WHERE id = ?
    `).bind(
      nextStep,
      isDone ? "completed" : "active",
      nextSendAt,
      sequenceRowId
    ).run();
  } catch (err3) {
    console.error("[emailEngine] advanceSequence error:", err3.message);
  }
}
