  free: { daily: 0, monthly: 0, rate_per_min: 0 },
  starter: { daily: 100, monthly: 2e3, rate_per_min: 10 },
  pro: { daily: 1e3, monthly: 2e4, rate_per_min: 60 },
  enterprise: { daily: -1, monthly: -1, rate_per_min: -1 }
